/**
 * User notification preferences model.
 *
 * Controls how and when a user receives email notifications.
 * Currently email is the only channel; the model is designed
 * so additional channels can be added later.
 */

export type NotificationCategory = 'order_confirmation' | 'order_status_update';

export type EmailFrequency = 'immediate' | 'daily_digest' | 'never';

export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;
  /** How often to deliver email notifications. */
  frequency: EmailFrequency;
  /** Categories the user has opted in to receive. */
  subscribedCategories: NotificationCategory[];
}

export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationCategory[];
}

export const ALL_NOTIFICATION_CATEGORIES: NotificationCategory[] = [
  'order_confirmation',
  'order_status_update',
];

export function createDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, EmailPreferences, NotificationCategory, EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        subscribedCategories: JSON.parse(record['emailSubscribedCategories'] as string) as NotificationCategory[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(entity.email.subscribedCategories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((pref) => pref.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD for preferences and a query method used by the
 * notification service to decide whether a notification should be sent.
 *
 * Depends on:
 * - PreferencesRepository (data access)
 * - UserRepository (validates user exists)
 */

import type { UserPreferences, UpdateEmailPreferencesInput, NotificationCategory } from '../models/user-preferences.js';
import { createDefaultEmailPreferences } from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private preferencesRepository: PreferencesRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get preferences for a user. Returns undefined if none have been created.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get or create preferences for a user.
   * If no preferences exist, creates defaults (all enabled, immediate delivery).
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: createDefaultEmailPreferences(),
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    this.logger.info(`Created default preferences for user ${userId}`);
    return preferences;
  }

  /**
   * Update email preferences for a user.
   */
  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserPreferences {
    const preferences = this.getOrCreatePreferences(userId);

    const updatedEmail = { ...preferences.email };
    if (input.enabled !== undefined) {
      updatedEmail.enabled = input.enabled;
    }
    if (input.frequency !== undefined) {
      updatedEmail.frequency = input.frequency;
    }
    if (input.subscribedCategories !== undefined) {
      updatedEmail.subscribedCategories = [...input.subscribedCategories];
    }

    const updated = this.preferencesRepository.update(preferences.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated email preferences for user ${userId}`);
    return updated;
  }

  /**
   * Check whether a notification should be sent to a user via email.
   *
   * Returns true if:
   * - The user has no preferences (defaults allow all notifications)
   * - Email is enabled AND frequency is 'immediate' AND the category is subscribed
   */
  shouldSendEmail(userId: string, category: NotificationCategory): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);

    // No preferences means defaults apply — send everything
    if (!preferences) {
      return true;
    }

    if (!preferences.email.enabled) {
      return false;
    }

    if (preferences.email.frequency !== 'immediate') {
      return false;
    }

    return preferences.email.subscribedCategories.includes(category);
  }
}

