import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import type { User } from '../../src/models/user.js';

const makeUser = (overrides?: Partial<User>): User => ({
  id: 'user-1',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date('2024-01-01'),
  updatedAt: new Date('2024-01-01'),
  ...overrides,
});

describe('PreferencesService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let prefsRepo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    prefsRepo = new PreferencesRepository(db);
    service = new PreferencesService(prefsRepo, userRepo);
    resetPreferencesIdCounter();
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for a user', () => {
      userRepo.save(makeUser());

      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
      ]);
    });

    it('should return existing preferences without creating duplicates', () => {
      userRepo.save(makeUser());

      const first = service.getOrCreatePreferences('user-1');
      const second = service.getOrCreatePreferences('user-1');

      expect(first.id).toBe(second.id);
    });

    it('should throw if user does not exist', () => {
      expect(() => service.getOrCreatePreferences('no-such-user')).toThrow(
        'User not found: no-such-user',
      );
    });
  });

  describe('getPreferences', () => {
    it('should return undefined when no preferences exist', () => {
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return preferences after creation', () => {
      userRepo.save(makeUser());
      service.getOrCreatePreferences('user-1');

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should disable email notifications', () => {
      userRepo.save(makeUser());

      const prefs = service.updateEmailPreferences('user-1', { enabled: false });

      expect(prefs.email.enabled).toBe(false);
      // Other fields unchanged
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
      ]);
    });

    it('should change frequency', () => {
      userRepo.save(makeUser());

      const prefs = service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });

      expect(prefs.email.frequency).toBe('daily_digest');
    });

    it('should update subscribed categories', () => {
      userRepo.save(makeUser());

      const prefs = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(prefs.email.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should apply multiple updates at once', () => {
      userRepo.save(makeUser());

      const prefs = service.updateEmailPreferences('user-1', {
        enabled: true,
        frequency: 'never',
        subscribedCategories: [],
      });

      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('never');
      expect(prefs.email.subscribedCategories).toEqual([]);
    });

    it('should create preferences if none exist', () => {
      userRepo.save(makeUser());

      const prefs = service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.frequency).toBe('daily_digest');
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (defaults)', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return true with default preferences', () => {
      userRepo.save(makeUser());
      service.getOrCreatePreferences('user-1');

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      userRepo.save(makeUser());
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when frequency is not immediate', () => {
      userRepo.save(makeUser());
      service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false for unsubscribed category', () => {
      userRepo.save(makeUser());
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(false);
    });

    it('should return false when frequency is never', () => {
      userRepo.save(makeUser());
      service.updateEmailPreferences('user-1', { frequency: 'never' });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });
  });

  describe('ID generation', () => {
    it('should generate sequential IDs', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));

      const prefs1 = service.getOrCreatePreferences('user-1');
      const prefs2 = service.getOrCreatePreferences('user-2');

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });
});
